SELECT p.product_id, p.category_id, c.category_name, p.product_code, p.product_name, p.product_subname, p.summary, p.description, p.thumbnail_url, p.status, p.is_featured, p.is_active, p.exposure_start_at, p.exposure_end_at, p.seo_title, p.seo_description, p.view_count, p.created_by, p.updated_by, p.created_at, p.updated_at FROM products p LEFT JOIN categories c ON p.category_id = c.category_id
AND p.category_id = #{search.categoryId}
AND p.status = #{search.status}
AND p.is_featured = #{search.isFeatured}
AND p.is_active = #{search.isActive}
AND ( p.product_name LIKE '%' || #{search.keyword} || '%' OR p.product_code LIKE '%' || #{search.keyword} || '%' )
ORDER BY p.created_at DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM products p


        AND p.category_id = #{search.categoryId}


        AND p.status = #{search.status}


        AND p.is_featured = #{search.isFeatured}


        AND p.is_active = #{search.isActive}


        AND (
            p.product_name LIKE '%' || #{search.keyword} || '%'
            OR p.product_code LIKE '%' || #{search.keyword} || '%'
        )

SELECT COUNT(*)
FROM products
WHERE product_code = #{productCode}

    AND product_id <> #{excludeId}
